 1	import React, { FC, MutableRefObject } from 'react';
 2	
 3	import { Popover } from '@patternfly/react-core';
 4	import { isEmpty } from '@utils/utils';
 5	
 6	import NetworkPolicyPodsPreview from './components/NetworkPolicyPodsPreview';
 7	
 8	type NetworkPolicySelectorPreviewProps = {
 9	  dataTest?: string;
10	  namespaceSelector?: string[][];
11	  podSelector: string[][];
12	  policyNamespace: string;
13	  popoverRef: MutableRefObject<undefined>;
14	};
15	
16	const NetworkPolicySelectorPreview: FC<NetworkPolicySelectorPreviewProps> = ({
17	  dataTest,
18	  namespaceSelector,
19	  podSelector,
20	  policyNamespace,
21	  popoverRef,
22	}) => {
23	  const allNamespaces = isEmpty(namespaceSelector?.filter((pair) => Boolean(pair?.[0])));
24	
25	  const AllNamespaceSelector = allNamespaces ? (
26	    <NetworkPolicyPodsPreview podSelector={podSelector} />
27	  ) : (
28	    <NetworkPolicyPodsPreview namespaceSelector={namespaceSelector} podSelector={podSelector} />
29	  );
30	
31	  return (
32	    <Popover
33	      aria-label="pods-list"
34	      bodyContent={
35	        namespaceSelector ? (
36	          AllNamespaceSelector
37	        ) : (
38	          <NetworkPolicyPodsPreview namespace={policyNamespace} podSelector={podSelector} />
39	        )
40	      }
41	      data-test={dataTest ? `${dataTest}-popover` : `pods-preview-popover`}
42	      position={'bottom'}
43	      triggerRef={popoverRef}
44	    />
45	  );
46	};
47	
48	export default NetworkPolicySelectorPreview;

